import React from 'react'

const Dashboard = React.lazy(() => import('../components/Dashboard/index'))
const UserManagement = React.lazy(() => import('../components/UserManagement/index'))
const CourseManagement = React.lazy(() => import('../components/CourseManagement/index'))
const ContentManagement = React.lazy(() => import('../components/ContentManagement/index'))
const LogOut = React.lazy(() => import('../components/LogOut/index'))



const routes = [
    { path: '/', exact: true, name: 'Home', element: <Dashboard /> },
    { path: '/dashboard', name: 'Dashboard', element: <Dashboard /> },
    { path: '/user-management', name: 'User Management', element: <UserManagement /> },
    { path: '/course-management', name: 'Course Management', element: <CourseManagement /> },
    { path: '/content-management', name: 'Content Management', element: <ContentManagement /> },
    { path: '/logout', name: 'Logout', element: <LogOut /> },

]

export default routes;
